from __future__ import annotations

import json
import os
import shutil
import subprocess
import sys
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
FRONTEND_APPS = [
    "apps/admin-dashboard",
    "apps/patient-portal",
    "apps/provider-portal",
    "apps/integration-console",
    "apps/public-website",
]
REQUIRED_DIRECTORIES = [
    "apps",
    "services",
    "packages",
    "schemas",
    "database",
    "infrastructure",
    "tests",
]
HELM_CHART = ROOT / "infrastructure/helm/healthbridge"
GO_SDK = ROOT / "packages/sdk-go"
DATABASE_SCHEMA = ROOT / "database/schema.sql"
DATABASE_MIGRATIONS = ROOT / "database/migrations"
DOCKER_COMPOSE_FILES = [ROOT / "docker-compose.yml"]


def run(command: list[str], cwd: Path = ROOT) -> None:
    cwd_display = "." if cwd == ROOT else cwd.relative_to(ROOT).as_posix()
    print(f"+ ({cwd_display}) {' '.join(command)}", flush=True)
    subprocess.run(command, cwd=cwd, check=True)


def skip(message: str) -> None:
    print(f"skipping {message}", flush=True)


def tool_available(name: str) -> bool:
    return shutil.which(name) is not None


def require_path(path: Path, description: str) -> None:
    if not path.exists():
        raise FileNotFoundError(f"missing {description}: {path.relative_to(ROOT)}")


def load_json(path: Path) -> object:
    with path.open(encoding="utf-8") as handle:
        return json.load(handle)


def verify_required_paths() -> None:
    for directory in REQUIRED_DIRECTORIES:
        require_path(ROOT / directory, f"project directory {directory}")

    root_manifest = ROOT / "package.json"
    root_lockfile = ROOT / "package-lock.json"
    require_path(root_manifest, "root npm workspace manifest")
    require_path(root_lockfile, "root npm lockfile")

    manifest = load_json(root_manifest)
    workspaces = manifest.get("workspaces") if isinstance(manifest, dict) else None
    if not isinstance(workspaces, list):
        raise ValueError("root package.json must define npm workspaces")

    missing_workspaces = sorted(set(FRONTEND_APPS) - set(workspaces))
    if missing_workspaces:
        raise ValueError(
            "root package.json missing frontend workspaces: "
            + ", ".join(missing_workspaces)
        )

    for app in FRONTEND_APPS:
        app_dir = ROOT / app
        require_path(app_dir, f"frontend app {app}")
        require_path(app_dir / "package.json", f"frontend manifest {app}/package.json")
        require_path(
            app_dir / "package-lock.json",
            f"frontend lockfile {app}/package-lock.json",
        )

    require_path(GO_SDK / "go.mod", "Go SDK module")
    require_path(HELM_CHART / "Chart.yaml", "Helm chart metadata")
    require_path(HELM_CHART / "values.yaml", "Helm values")
    require_path(DATABASE_SCHEMA, "database schema")
    require_path(DATABASE_MIGRATIONS, "database migrations directory")
    for compose_file in DOCKER_COMPOSE_FILES:
        require_path(compose_file, f"Docker compose file {compose_file.name}")


def validate_json() -> None:
    count = 0
    for path in ROOT.rglob("*.json"):
        if "node_modules" in path.parts or "dist" in path.parts:
            continue
        load_json(path)
        count += 1
    print(f"validated {count} json files")


def is_helm_template(path: Path) -> bool:
    return (
        "infrastructure" in path.parts
        and "helm" in path.parts
        and "templates" in path.parts
    )


def validate_yaml() -> None:
    try:
        import yaml
    except Exception as exc:
        skip(f"yaml validation: {exc}")
        return

    count = 0
    for pattern in ("*.yaml", "*.yml"):
        for path in ROOT.rglob(pattern):
            if "node_modules" in path.parts or "dist" in path.parts:
                continue
            if is_helm_template(path):
                continue
            with path.open(encoding="utf-8") as handle:
                yaml.safe_load(handle)
            count += 1
    print(f"validated {count} non-template yaml files")


def run_services() -> None:
    for app in sorted((ROOT / "services").glob("*/app.py")):
        run([sys.executable, str(app)])


def run_frontends() -> None:
    run(["npm", "test"])
    run(["npm", "run", "build"])


def verify_go_sdk() -> None:
    if not tool_available("go"):
        skip("Go SDK tests: go not installed")
        return
    run(["go", "test", "./..."], cwd=GO_SDK)


def verify_helm_chart() -> None:
    chart = load_yaml_file(HELM_CHART / "Chart.yaml")
    if chart is None:
        chart = load_top_level_yaml_scalars(HELM_CHART / "Chart.yaml")

    if not isinstance(chart, dict):
        raise ValueError("Helm Chart.yaml must be a mapping")
    for key in ("apiVersion", "name", "version", "type"):
        if not chart.get(key):
            raise ValueError(f"Helm Chart.yaml missing required key: {key}")

    if not tool_available("helm"):
        skip("Helm lint: helm not installed")
        return
    run(["helm", "lint", str(HELM_CHART)])


def load_yaml_file(path: Path) -> object:
    try:
        import yaml
    except Exception as exc:
        skip(f"yaml-backed check for {path.relative_to(ROOT)}: {exc}")
        return None

    with path.open(encoding="utf-8") as handle:
        return yaml.safe_load(handle)


def load_top_level_yaml_scalars(path: Path) -> dict[str, str]:
    values: dict[str, str] = {}
    for line in path.read_text(encoding="utf-8").splitlines():
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            continue
        if line[:1].isspace() or stripped.startswith("-"):
            continue
        key, separator, value = stripped.partition(":")
        if separator:
            values[key.strip()] = value.strip().strip("\"'")
    return values


def verify_database_schema() -> None:
    sql_files = [DATABASE_SCHEMA, *sorted(DATABASE_MIGRATIONS.glob("*.sql"))]
    if len(sql_files) == 1:
        raise FileNotFoundError("database/migrations must contain at least one SQL file")

    for path in sql_files:
        text = path.read_text(encoding="utf-8").strip()
        if not text:
            raise ValueError(f"database SQL file is empty: {path.relative_to(ROOT)}")
    schema_text = DATABASE_SCHEMA.read_text(encoding="utf-8").upper()
    if "CREATE TABLE" not in schema_text:
        raise ValueError("database/schema.sql must define database tables")
    print(f"verified {len(sql_files)} database sql files")

    if not tool_available("psql"):
        skip("database schema apply: psql not installed")
        return

    database_url = os.environ.get("HEALTHBRIDGE_VERIFY_DATABASE_URL")
    if not database_url:
        skip(
            "database schema apply: HEALTHBRIDGE_VERIFY_DATABASE_URL is not set"
        )
        return

    run(
        [
            "psql",
            "--no-psqlrc",
            "--set",
            "ON_ERROR_STOP=1",
            "--dbname",
            database_url,
            "--file",
            str(DATABASE_SCHEMA),
        ]
    )


def docker_daemon_available() -> bool:
    try:
        subprocess.run(
            ["docker", "info", "--format", "{{.ServerVersion}}"],
            cwd=ROOT,
            check=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
        )
    except subprocess.CalledProcessError as exc:
        detail = (exc.stderr or exc.stdout).strip().splitlines()
        suffix = f": {detail[-1]}" if detail else ""
        skip(f"Docker build checks: docker daemon unavailable{suffix}")
        return False
    return True


def verify_docker_inputs() -> None:
    dockerfiles = sorted((ROOT / "services").glob("*/Dockerfile"))
    if not dockerfiles:
        raise FileNotFoundError("services must contain Dockerfiles")

    service_dirs = sorted(path for path in (ROOT / "services").iterdir() if path.is_dir())
    for service_dir in service_dirs:
        require_path(service_dir / "Dockerfile", f"{service_dir.name} Dockerfile")
        require_path(service_dir / "app.py", f"{service_dir.name} service entrypoint")

    for dockerfile in dockerfiles:
        text = dockerfile.read_text(encoding="utf-8")
        if "FROM " not in text or "CMD " not in text:
            raise ValueError(
                f"Dockerfile must include FROM and CMD: {dockerfile.relative_to(ROOT)}"
            )

    compose = load_yaml_file(ROOT / "docker-compose.yml")
    if isinstance(compose, dict):
        services = compose.get("services")
        if not isinstance(services, dict) or not services:
            raise ValueError("docker-compose.yml must define services")
        for name, definition in services.items():
            if isinstance(definition, dict) and "build" in definition:
                build_path = ROOT / str(definition["build"])
                require_path(build_path, f"Docker build context for {name}")

    print(f"verified {len(dockerfiles)} service Dockerfiles")

    if not tool_available("docker"):
        skip("Docker build checks: docker not installed")
        return
    if not docker_daemon_available():
        return

    for dockerfile in dockerfiles:
        context = dockerfile.parent
        tag = f"healthbridge-verify-{context.name}"
        run(
            [
                "docker",
                "build",
                "--pull=false",
                "--tag",
                tag,
                "--file",
                str(dockerfile),
                str(context),
            ]
        )


def main() -> None:
    verify_required_paths()
    run([sys.executable, "-m", "compileall", "-q", "services", "packages", "scripts"])
    run([sys.executable, "-m", "pytest", "-q"])
    validate_json()
    validate_yaml()
    run_services()
    run_frontends()
    verify_go_sdk()
    verify_helm_chart()
    verify_database_schema()
    verify_docker_inputs()


if __name__ == "__main__":
    main()
